import{_ as s,c as a,o as e,d as m}from"./plugin-vue_export-helper.bd4ff235.js";const h='{"title":"\u0413\u043B\u0430\u0432\u0430 7","description":"","frontmatter":{"title":"\u0413\u043B\u0430\u0432\u0430 7","subtitle":"\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0430","tags":"malini","date":"2020-09-30T00:00:00.000Z"},"headers":[],"relativePath":"texts/malini-vijayottara/7.md","lastUpdated":1625428838000}',i={},d=m('<div class="stanza"><a href="#s7.1" id="s7.1" class="num">7.1</a><p>\u0428\u0438\u0432\u0430 \u0441\u043A\u0430\u0437\u0430\u043B:</p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043F\u043E\u0432\u0435\u0434\u0430\u044E \u043E \u043C\u0443\u0434\u0440\u0430\u0445 \u0428\u0438\u0432\u044B \u0438 \u0428\u0430\u043A\u0442\u0438, \u0437\u0430\u0449\u0438\u0442\u0438\u0432\u0448\u0438\u0441\u044C \u043A\u043E\u0442\u043E\u0440\u044B\u043C\u0438, \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u044F\u0449\u0438\u0439 \u043C\u0430\u043D\u0442\u0440\u0443 (\u0441\u0430\u0434\u0445\u0430\u043A\u0430) \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0432\u0441\u0435 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u0430 .</p></div><div class="stanza"><a href="#s7.2-4" id="s7.2-4" class="num">7.2-4</a><p><em>\u0422\u0440\u0438\u0448\u0443\u043B\u0430, \u043F\u0430\u0434\u043C\u0430, \u0448\u0430\u043A\u0442\u0438, \u0447\u0430\u043A\u0440\u0430, \u0432\u0430\u0434\u0436\u0440\u0430, \u0434\u0430\u043D\u0434\u0430, \u0434\u0430\u043C\u0448\u0442\u0440\u0430, \u043C\u0430\u0445\u0430\u043F\u0440\u0435\u0442\u0430, \u043C\u0430\u0445\u0430\u043C\u0443\u0434\u0440\u0430, \u043A\u0445\u0430\u0433\u0430\u0438\u0448\u0432\u0430\u0440\u0438, \u043C\u0430\u0445\u043E\u0434\u0430\u0439\u0430, \u043A\u0430\u0440\u0430\u043B\u0430, \u043A\u0445\u0430\u0442\u0432\u0430\u043D\u0433\u0430, \u043A\u0430\u043F\u0430\u043B\u0430\u043A\u0430, \u0445\u0430\u043B\u0430, \u043F\u0430\u0448\u0430, \u0430\u043D\u043A\u0443\u0448\u0430, \u0433\u0445\u0430\u043D\u0442\u0430, \u043C\u0443\u0434\u0433\u0430\u0440\u0430, \u0442\u0440\u0438\u0448\u0438\u043A\u0445\u0430, \u0430\u0432\u0430\u0445\u0430\u043D\u0430, \u0441\u0442\u0445\u0430\u043F\u0430\u043D\u0430, \u043D\u0438\u0440\u043E\u0434\u0445\u0430, \u0434\u0440\u0430\u0432\u044C\u044F\u0434\u0430</em> \u0438 <em>\u043D\u0430\u0442\u0438</em> \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B \u043A\u0430\u043A \u0431\u0435\u0441\u0447\u0438\u0441\u043B\u0435\u043D\u043D\u044B\u0435 \u0439\u043E\u0433\u0430 \u043C\u0443\u0434\u0440\u044B, \u043E \u041F\u043E\u0447\u0438\u0442\u0430\u0435\u043C\u0430\u044F \u0433\u0435\u0440\u043E\u044F\u043C\u0438!</p></div><div class="stanza"><a href="#s7.5" id="s7.5" class="num">7.5</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u043E\u0442\u0442\u044F\u043D\u0443\u0442\u044C \u0443\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0439, \u0441\u0440\u0435\u0434\u043D\u0438\u0439 \u0438 \u0431\u0435\u0437\u044B\u043C\u044F\u043D\u043D\u044B\u0439 \u043F\u0430\u043B\u0435\u0446 \u043F\u0440\u0430\u0432\u043E\u0439 (\u0440\u0443\u043A\u0438), \u0438 \u0441\u043E\u0435\u0434\u0438\u043D\u0438\u0442\u044C \u0431\u043E\u043B\u044C\u0448\u043E\u0439 \u043F\u0430\u043B\u0435\u0446 \u0441 \u043C\u0438\u0437\u0438\u043D\u0446\u0435\u043C. \u042D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F <em>\u0442\u0440\u0438\u0448\u0443\u043B\u0430 (\u043C\u0443\u0434\u0440\u043E\u0439</em>) .</p></div><div class="stanza"><a href="#s7.6\u0431-7\u0430" id="s7.6\u0431-7\u0430" class="num">7.6\u0431-7\u0430</a><p>\u0421\u043B\u043E\u0436\u0438\u0432 \u0440\u0443\u043A\u0438 \u0432 \u0444\u043E\u0440\u043C\u0435 \u043B\u043E\u0442\u043E\u0441\u0430, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043A\u0430\u0437\u0430\u0442\u044C <em>\u043F\u0430\u0434\u043C\u0430 \u043C\u0443\u0434\u0440\u0443</em> ..6\u0430.</p><p>\u0412\u044B\u0442\u044F\u043D\u0443\u0442\u044B\u0435 (\u0432 \u043F\u0430\u0434\u043C\u0430 \u043C\u0443\u0434\u0440\u0435) \u043F\u0430\u043B\u044C\u0446\u044B \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043D\u0430\u043F\u0440\u0430\u0432\u0438\u0442\u044C \u0432\u043D\u0443\u0442\u0440\u044C, \u0421\u0440\u0435\u0434\u043D\u0438\u0435 \u043F\u0430\u043B\u044C\u0446\u044B (\u043E\u0441\u0442\u0430\u044E\u0442\u0441\u044F) \u0432\u044B\u0442\u044F\u043D\u0443\u0442\u044B. \u042D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F <em>\u043C\u0443\u0434\u0440\u043E\u0439 \u041A\u0443\u043C\u0430\u0440\u0438 \u0428\u0430\u043A\u0442\u0438</em> ...</p><div class="stanza"><a href="#s7.7" id="s7.7" class="num">7.7</a><p>\u041D\u0430 \u0442\u044B\u043B\u044C\u043D\u0443\u044E \u0441\u0442\u043E\u0440\u043E\u043D\u0443 \u043B\u0435\u0432\u043E\u0433\u043E \u043A\u0443\u043B\u0430\u043A\u0430 \u043A\u043B\u0430\u0434\u0435\u0442\u0441\u044F \u043F\u0440\u0430\u0432\u044B\u0439 (<em>\u0434\u0430\u043B\u0435\u0435 \u0442\u0435\u043A\u0441\u0442 \u043F\u043E\u0432\u0440\u0435\u0436\u0434\u0435\u043D</em>)</p></div></div><div class="stanza"><a href="#s7.8" id="s7.8" class="num">7.8</a><p>\u0421\u0432\u0435\u0440\u0445\u0443 \u0442\u044B\u043B\u044C\u043D\u043E\u0439 \u0441\u0442\u043E\u0440\u043E\u043D\u044B \u043B\u0435\u0432\u043E\u0439 \u043B\u0430\u0434\u043E\u043D\u0438 \u043A\u043B\u0430\u0434\u0435\u0442\u0441\u044F \u043F\u0440\u0430\u0432\u0430\u044F \u0440\u0443\u043A\u0430 \u043B\u0430\u0434\u043E\u043D\u044C\u044E \u0432\u043D\u0438\u0437 (<em>\u0442\u0435\u043A\u0441\u0442 \u043F\u043E\u0432\u0440\u0435\u0436\u0434\u0435\u043D</em>) .</p></div><div class="stanza"><a href="#s7.9" id="s7.9" class="num">7.9</a><p>\u0420\u0430\u0437\u0432\u0435\u0434\u044F \u0431\u043E\u043B\u044C\u0448\u043E\u0439 (\u043F\u0430\u043B\u0435\u0446) \u0438 \u043C\u0438\u0437\u0438\u043D\u0435\u0446 (\u0432 \u0441\u0442\u043E\u0440\u043E\u043D\u044B), \u043E\u0441\u0442\u0430\u0432\u0448\u0438\u0435\u0441\u044F (\u043F\u0430\u043B\u044C\u0446\u044B) \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043A \u0437\u0430\u043F\u044F\u0441\u0442\u044C\u044E (\u0441\u0436\u0438\u043C\u0430\u044E\u0442\u0441\u044F \u0432 \u043A\u0443\u043B\u0430\u043A). \u042D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F <em>\u043B\u0443\u043D\u043D\u043E\u0439 \u0432\u0430\u0434\u0436\u0440\u0430 \u043C\u0443\u0434\u0440\u043E\u0439</em>, \u0442\u0432\u043E\u0440\u044F\u0449\u0435\u0439 \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 .</p></div><div class="stanza"><a href="#s7.10" id="s7.10" class="num">7.10</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0434\u043D\u044F\u0442\u044C \u0432\u0432\u0435\u0440\u0445 \u043F\u0440\u0430\u0432\u0443\u044E \u0440\u0443\u043A\u0443 \u0441 \u0431\u043E\u043B\u044C\u0448\u0438\u043C \u043F\u0430\u043B\u044C\u0446\u0435\u043C, \u0437\u0430\u0436\u0430\u0442\u044B\u043C \u0432 \u043A\u0443\u043B\u0430\u043A\u0435. \u042D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F <em>\u0434\u0430\u043D\u0434\u0430 \u043C\u0443\u0434\u0440\u043E\u0439</em>, \u0412\u0438\u0432\u0430\u0441\u0432\u0430\u0442\u043E\u0439, \u043B\u044E\u0431\u0438\u043C\u043E\u0439 \u041A\u0443\u043B\u043E\u0439 .</p></div><div class="stanza"><a href="#s7.11" id="s7.11" class="num">7.11</a><p>\u0420\u0430\u0437\u0432\u0435\u0440\u043D\u0443\u0432 \u043B\u0435\u0432\u044B\u0439 (\u0438 \u043F\u0440\u0430\u0432\u044B\u0439) \u043A\u0443\u043B\u0430\u043A\u0438 \u043A \u043B\u0438\u0446\u0443, \u043C\u0438\u0437\u0438\u043D\u0446\u044B \u043E\u0442\u0432\u043E\u0434\u044F\u0442\u0441\u044F \u0432 \u0441\u0442\u043E\u0440\u043E\u043D\u0443 \u043E\u0442 \u043A\u0443\u043B\u0430\u043A\u0430. \u042D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F, \u043E \u0414\u0435\u0432\u0438, <em>\u0434\u0430\u043C\u0448\u0442\u0440\u0430 \u043C\u0443\u0434\u0440\u043E\u0439</em>, \u0427\u0430\u043C\u0443\u043D\u0434\u043E\u0439, \u0420\u0430\u0434\u0443\u044E\u0449\u0435\u0439 \u041A\u0443\u043B\u0443 .</p></div><div class="stanza"><a href="#s7.12-13\u0430" id="s7.12-13\u0430" class="num">7.12-13\u0430</a><p>\u041D\u0430 \u043B\u0435\u0432\u043E\u0435 \u043A\u043E\u043B\u0435\u043D\u043E \u043A\u043B\u0430\u0434\u0435\u0442\u0441\u044F \u0441\u0442\u043E\u043F\u0430. \u041D\u0430 \u043D\u0435\u0435 \u043E\u043F\u0443\u0441\u043A\u0430\u044E\u0442\u0441\u044F \u043A\u0438\u0441\u0442\u0438. \u0412\u0437\u0433\u043B\u044F\u0434 \u043D\u0435 \u043C\u0438\u0433\u0430\u0435\u0442, \u0448\u0435\u044F \u043F\u043E\u0434\u043E\u0433\u043D\u0443\u0442\u0430, \u044F\u0437\u044B\u043A \u0432\u044B\u0441\u0443\u043D\u0443\u0442.(\u042D\u0442\u0430 \u043C\u0443\u0434\u0440\u0430) \u043B\u044E\u0431\u0438\u043C\u0430\u044F \u0441\u043E\u043D\u043C\u043E\u043C \u0439\u043E\u0433\u0438\u043D\u043E\u0432, \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F <em>\u0419\u043E\u0433\u0435\u0448\u0432\u0430\u0440\u0438</em>(\u0412\u043B\u0430\u0434\u044B\u0447\u0438\u0446\u0435\u0439 \u0439\u043E\u0433\u0438) .</p></div><div class="stanza"><a href="#s7.14-15\u0430" id="s7.14-15\u0430" class="num">7.14-15\u0430</a><p>\u041F\u0443\u0441\u0442\u044C \u043C\u0443\u0434\u0440\u044B\u0439 \u0434\u0432\u0438\u0433\u0430\u0435\u0442 \u0440\u0443\u043A\u0438 (\u043E\u0431\u0440\u0430\u0449\u0435\u043D\u043D\u044B\u0435) \u043B\u0430\u0434\u043E\u043D\u044F\u043C\u0438 \u0432\u043D\u0438\u0437 \u043E\u0442 \u0441\u0442\u043E\u043F \u0434\u043E \u0441\u0435\u0440\u0434\u0446\u0430. \u041F\u0435\u0440\u0435\u0434 \u043B\u0438\u0446\u043E\u043C \u043E\u043D\u0438 \u0440\u0430\u0437\u0432\u043E\u0434\u044F\u0442\u0441\u044F \u0432 \u0441\u0442\u043E\u0440\u043E\u043D\u044B, \u0432\u0432\u0435\u0440\u0445\u0443 (\u043D\u0430\u0434 \u0433\u043E\u043B\u043E\u0432\u043E\u0439) \u0438\u0445 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043B\u043E\u0436\u0438\u0442\u044C \u0432\u043C\u0435\u0441\u0442\u0435. \u042D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F <em>\u043C\u0430\u0445\u0430 \u043C\u0443\u0434\u0440\u043E\u0439</em>, \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u043C\u043E\u0439 \u0432 \u043E\u0431\u0440\u044F\u0434\u0435 \u043E\u0447\u0438\u0449\u0435\u043D\u0438\u044F \u0442\u0435\u043B\u0430. \u041E\u043D\u0430 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442\u0441\u044F \u0439\u043E\u0433\u0438\u043D\u0430\u043C\u0438 \u043F\u0440\u0438 \u0432\u0441\u0435\u0445 \u043E\u0431\u0440\u044F\u0434\u0430\u0445 \u0440\u0430\u0434\u0438 \u0443\u0441\u043F\u0435\u0445\u0430 \u0432 \u0439\u043E\u0433\u0435 .</p></div><div class="stanza"><a href="#s7.15\u0431-17\u0430" id="s7.15\u0431-17\u0430" class="num">7.15\u0431-17\u0430</a><p>\u041F\u0440\u0438\u043D\u044F\u0432 \u043F\u043E\u0437\u0443 \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0433\u043E \u043B\u043E\u0442\u043E\u0441\u0430, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u0432\u043B\u0430\u0434\u044B\u043A\u0443 \u0447\u0443\u0432\u0441\u0442\u0432 (\u044F\u0437\u044B\u043A) \u0432 \u043D\u0435\u0431\u043E. \u0412\u044B\u0442\u044F\u043D\u0443\u0432 \u0442\u0435\u043B\u043E (\u043F\u0440\u044F\u043C\u043E) \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u043F\u0430\u043B\u043A\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0431\u044B\u0441\u0442\u0440\u043E \u0432\u0435\u0441\u0442\u0438 (\u041A\u0443\u043D\u0434\u0430\u043B\u0438\u043D\u0438 \u0428\u0430\u043A\u0442\u0438) \u0447\u0435\u0440\u0435\u0437 \u0442\u0440\u0438 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0430 (<em>\u0442.\u0435. \u0428\u0430\u043A\u0442\u0438, \u0432\u044C\u044F\u043F\u0438\u043D\u0438 \u0438 \u0441\u0430\u043C\u0430\u043D\u0430,</em> <em>\u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u043D\u044B\u0445</em> <em>\u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u043C\u0435\u0436\u0431\u0440\u043E\u0432\u0438\u044F \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F \u0431\u0440\u0430\u0445\u043C\u0430\u0440\u0430\u043D\u0434\u0445\u0440\u043E\u0439</em>). \u041F\u0440\u0438\u043D\u044F\u0432 \u0442\u0430\u043A\u0443\u044E \u0430\u0441\u0430\u043D\u0443, \u0432\u0435\u043B\u0438\u043A\u0438\u0439 \u0439\u043E\u0433\u0438\u043D \u043E\u0431\u0440\u0435\u0442\u0451\u0442 \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0435 \u043F\u043E \u043D\u0435\u0431\u0443. (<em>\u0422\u0430\u043A \u043E\u043F\u0438\u0441\u0430\u043D\u0430 \u041A\u0445\u0435\u0447\u0430\u0440\u0438 \u043C\u0443\u0434\u0440\u0430</em>) .</p></div><div class="stanza"><a href="#s7.17\u0431-19" id="s7.17\u0431-19" class="num">7.17\u0431-19</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0435\u0434\u0438\u043D\u0438\u0442\u044C \u0441\u0440\u0435\u0434\u043D\u0438\u0439 \u0438 \u0431\u0435\u0437\u044B\u043C\u044F\u043D\u043D\u044B\u0439 \u043F\u0430\u043B\u0435\u0446 \u043B\u0435\u0432\u043E\u0439 \u0440\u0443\u043A\u0438 \u0441 \u0431\u043E\u043B\u044C\u0448\u0438\u043C \u043F\u0430\u043B\u044C\u0446\u0435\u043C, \u043C\u0438\u0437\u0438\u043D\u0435\u0446 \u0438 \u0443\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0439 \u0441 \u043C\u0438\u0437\u0438\u043D\u0446\u0435\u043C \u0438 \u0443\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u043C \u043F\u0430\u043B\u044C\u0446\u0435\u043C (\u043F\u0440\u0430\u0432\u043E\u0439 \u0440\u0443\u043A\u0438, \u0443 \u043A\u043E\u0442\u043E\u0440\u043E\u0439) \u0441\u0440\u0435\u0434\u043D\u0438\u0439 \u0438 \u0431\u0435\u0437\u044B\u043C\u0435\u043D\u043D\u044B\u0439 \u043F\u0430\u043B\u0435\u0446 \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u044B \u0441 \u0431\u043E\u043B\u044C\u0448\u0438\u043C \u043F\u0430\u043B\u044C\u0446\u0435\u043C. \u042D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F <em>\u043C\u0430\u0445\u043E\u0434\u0430\u044F \u043C\u0443\u0434\u0440\u043E\u0439</em>, \u0442\u0432\u043E\u0440\u044F\u0449\u0435\u0439 \u0434\u043B\u044F \u043B\u044E\u0434\u0435\u0439 \u0432\u0435\u043B\u0438\u043A\u043E\u0435 \u0432\u043E\u0437\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0435 .</p></div><div class="stanza"><a href="#s7.20-21\u0430" id="s7.20-21\u0430" class="num">7.20-21\u0430</a><p>\u041C\u0438\u0437\u0438\u043D\u0446\u0430\u043C\u0438 \u0438 \u0431\u0435\u0437\u044B\u043C\u044F\u043D\u043D\u044B\u043C\u0438 \u043F\u0430\u043B\u044C\u0446\u0430\u043C\u0438 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043E\u0442\u0442\u044F\u043D\u0443\u0442\u044C \u0443\u0433\u043E\u043B\u043A\u0438 \u0433\u0443\u0431 \u0438 \u0434\u0432\u0438\u0433\u0430\u0442\u044C \u044F\u0437\u044B\u043A\u043E\u043C (\u043A\u0430\u043A \u0431\u044B) \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u044F \u0437\u0432\u0443\u043A \u0425\u0410-\u0425\u0410. \u042D\u0442\u0430 \u0441\u0442\u0440\u0430\u0448\u043D\u0430\u044F \u043D\u0430 \u0432\u0438\u0434 <em>\u043A\u0430\u0440\u0430\u043B\u0430 \u043C\u0443\u0434\u0440\u0430</em> \u0442\u0432\u043E\u0440\u0438\u0442 \u0441\u0442\u0440\u0430\u0445 \u0432\u0440\u0430\u0433\u0430\u043C .</p></div><div class="stanza"><a href="#s7.21\u0431-22\u0430" id="s7.21\u0431-22\u0430" class="num">7.21\u0431-22\u0430</a><p>(\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u0436\u0430\u0442\u044C) \u043B\u0435\u0432\u0443\u044E \u0440\u0443\u043A\u0443 \u0432 \u043A\u0443\u043B\u0430\u043A, \u043C\u0438\u0437\u0438\u043D\u0435\u0446 \u043F\u043E\u0434\u043D\u044F\u0442 \u0432\u0432\u0435\u0440\u0445. \u042D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F <em>\u043A\u0445\u0430\u0442\u0432\u0430\u043D\u0433\u0430 \u043C\u0443\u0434\u0440\u043E\u0439</em>, \u0442\u0435\u043F\u0435\u0440\u044C \u0432\u044B\u0441\u043B\u0443\u0448\u0430\u0439 \u043E <em>\u043A\u0430\u043F\u0430\u043B\u0430 (\u043C\u0443\u0434\u0440\u0435)</em> .</p></div><div class="stanza"><a href="#s7.22\u0431-23a" id="s7.22\u0431-23a" class="num">7.22\u0431-23a</a><p>\u041F\u0440\u0430\u0432\u0430\u044F \u043B\u0430\u0434\u043E\u043D\u044C (\u043E\u0431\u0440\u0430\u0449\u0435\u043D\u0430) \u0432\u043D\u0438\u0437, \u043F\u0430\u043B\u044C\u0446\u044B \u0441\u043B\u0435\u0433\u043A\u0430 \u0441\u043E\u043F\u0440\u0438\u043A\u0430\u0441\u0430\u044E\u0442\u0441\u044F. \u042D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F <em>\u043A\u0430\u043F\u0430\u043B\u0430 (\u043C\u0443\u0434\u0440\u043E\u0439)</em>, \u0442\u0435\u043F\u0435\u0440\u044C \u0443\u0441\u043B\u044B\u0448\u044C \u043E <em>\u0445\u0430\u043B\u0430 \u043C\u0443\u0434\u0440\u0435</em> (\u043C\u0443\u0434\u0440\u0430 \u043F\u043B\u0443\u0433\u0430) .</p></div><div class="stanza"><a href="#s7.23-24\u0430" id="s7.23-24\u0430" class="num">7.23-24\u0430</a><p>\u041F\u0440\u0430\u0432\u043E\u0439 \u0440\u0443\u043A\u043E\u0439 \u0437\u0430\u0436\u0430\u0442\u043E\u0439 \u0432 \u043A\u0443\u043B\u0430\u043A \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043E\u0445\u0432\u0430\u0442\u0438\u0442\u044C \u0443\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0439 \u043F\u0430\u043B\u0435\u0446 \u043B\u0435\u0432\u043E\u0439 \u0440\u0443\u043A\u0438 (\u043F\u043E\u0434\u043E\u0431\u043D\u043E) \u0440\u0442\u0443, \u044D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F <em>\u0445\u0430\u043B\u0430 \u043C\u0443\u0434\u0440\u043E\u0439</em> (\u043C\u0443\u0434\u0440\u043E\u0439 \u043F\u043B\u0443\u0433\u0430) .</p></div><div class="stanza"><a href="#s7.24\u0431-25\u0430" id="s7.24\u0431-25\u0430" class="num">7.24\u0431-25\u0430</a><p>\u041F\u0440\u0430\u0432\u044B\u0439 \u0438 \u043B\u0435\u0432\u044B\u0439 \u043A\u0443\u043B\u0430\u043A\u0438 \u0441\u0436\u0430\u0442\u044B, \u043E\u0431\u0430 \u0443\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0445 \u043F\u0430\u043B\u044C\u0446\u0435\u0432 \u043F\u0435\u0440\u0435\u043F\u043B\u0435\u0442\u0435\u043D\u044B, \u043A\u043E\u043D\u0447\u0438\u043A \u043B\u0435\u0432\u043E\u0433\u043E \u0431\u043E\u043B\u044C\u0448\u043E\u0433\u043E \u043F\u0430\u043B\u044C\u0446\u0430 \u0441\u043E\u043F\u0440\u0438\u043A\u0430\u0441\u0430\u0435\u0442\u0441\u044F (\u0441 \u043A\u043E\u043D\u0447\u0438\u043A\u043E\u043C \u0443\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u043F\u0430\u043B\u044C\u0446\u0430 \u043F\u0440\u0430\u0432\u043E\u0439). \u042D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F <em>\u043F\u0430\u0448\u0430 \u043C\u0443\u0434\u0440\u043E\u0439</em>, \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0438\u0432\u0430\u044E\u0449\u0435\u0439 \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u0435 .</p></div><div class="stanza"><a href="#s7.25\u0431" id="s7.25\u0431" class="num">7.25\u0431</a><p>\u041A\u043E\u0433\u0434\u0430 \u043B\u0435\u0432\u044B\u0439 \u043A\u0443\u043B\u0430\u043A \u043F\u0440\u0438 \u0445\u0430\u043B\u0430 (\u043C\u0443\u0434\u0440\u0435\u0435) \u043B\u0438\u0448\u0435\u043D \u043F\u0440\u0430\u0432\u043E\u0433\u043E (\u043A\u0443\u043B\u0430\u043A\u0430), \u044D\u0442\u043E (\u0431\u0443\u0434\u0435\u0442) <em>\u0430\u043D\u043A\u0443\u0448\u0430 (\u043C\u0443\u0434\u0440\u0430)</em>.</p></div><div class="stanza"><a href="#s7.26" id="s7.26" class="num">7.26</a><p>\u041F\u0443\u0441\u0442\u044C \u043C\u0443\u0434\u0440\u044B\u0439 \u043F\u0440\u043E\u0441\u0443\u043D\u0435\u0442 \u0443\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0439 \u043F\u0430\u043B\u0435\u0446 \u043F\u0440\u0430\u0432\u043E\u0439 \u0440\u0443\u043A\u0438 (\u0441\u0432\u0435\u0440\u0445\u0443), \u0447\u0435\u0440\u0435\u0437 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0443 \u043F\u0430\u043B\u044C\u0446\u0435\u0432 (<em>\u043C\u0435\u0436\u0434\u0443 \u0441\u0440\u0435\u0434\u043D\u0438\u043C \u0438 \u0431\u0435\u0437\u044B\u043C\u044F\u043D\u043D\u044B\u043C \u043F\u0430\u043B\u044C\u0446\u0430\u043C\u0438</em>) \u043B\u0435\u0432\u043E\u0439, \u043E\u0431\u0440\u0430\u0449\u0435\u043D\u043D\u043E\u0439 \u043B\u0430\u0434\u043E\u043D\u044C\u044E \u0432\u043D\u0438\u0437. \u042D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0431\u043B\u0430\u0433\u043E\u043F\u0440\u0438\u044F\u0442\u043D\u043E\u0439 <em>\u0433\u0445\u0430\u043D\u0442\u0430 \u043C\u0443\u0434\u0440\u043E\u0439</em> (\u043C\u0443\u0434\u0440\u043E\u0439 \u043A\u043E\u043B\u043E\u043A\u043E\u043B\u0430) .</p></div><div class="stanza"><a href="#s7.27" id="s7.27" class="num">7.27</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0432\u0435\u0440\u043D\u0443\u0442\u044C \u0440\u0443\u043A\u0438 \u043B\u0430\u0434\u043E\u043D\u044F\u043C\u0438 \u0432\u0432\u0435\u0440\u0445, \u0441 \u043F\u0430\u043B\u044C\u0446\u0430\u043C\u0438, \u043F\u0435\u0440\u0435\u043F\u043B\u0435\u0442\u0435\u043D\u043D\u044B\u043C\u0438 \u0434\u0440\u0443\u0433 \u0441 \u0434\u0440\u0443\u0433\u043E\u043C \u0438 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u043D\u044B\u043C\u0438 \u0432\u043D\u0443\u0442\u0440\u044C. \u0411\u0435\u0437\u044B\u043C\u044F\u043D\u043D\u044B\u0435 \u043F\u0430\u043B\u044C\u0446\u044B \u0434\u043E\u043B\u0436\u0435\u043D \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u043D\u0430 \u0442\u044B\u043B\u044C\u043D\u043E\u0439 \u0441\u0442\u043E\u0440\u043E\u043D\u0435 \u0441\u0440\u0435\u0434\u043D\u0438\u0445, \u0443\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0435 \u043F\u0430\u043B\u044C\u0446\u044B \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u044B \u0441 \u0431\u043E\u043B\u044C\u0448\u0438\u043C\u0438 \u043F\u0430\u043B\u044C\u0446\u0430\u043C\u0438 .</p></div><div class="stanza"><a href="#s7.28-29a" id="s7.28-29a" class="num">7.28-29a</a><p>\u0414\u0432\u0430 \u0441\u0440\u0435\u0434\u043D\u0438\u0445 \u043F\u0430\u043B\u044C\u0446\u0430 \u0441\u043E\u0431\u0440\u0430\u043D\u044B \u0432\u043C\u0435\u0441\u0442\u0435. \u041C\u0438\u0437\u0438\u043D\u0446\u044B \u0438 \u0443\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0435 \u043F\u0430\u043B\u044C\u0446\u044B \u043E\u0442\u043E\u0433\u043D\u0443\u0442\u044B \u0432 \u0441\u0442\u043E\u0440\u043E\u043D\u044B \u043E\u0442 \u0441\u0440\u0435\u0434\u043D\u0438\u0445 \u043F\u0430\u043B\u044C\u0446\u0435\u0432. \u042D\u0442\u043E _\u043C\u0443\u0434\u0433\u0430\u0440\u0430 _\u0438 <em>\u0442\u0440\u0438\u0448\u0438\u043A\u0445\u0430 (\u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430\u044F \u0442\u0430\u043A \u0436\u0435, \u043A\u0430\u043A \u0439\u043E\u043D\u0438)__(\u043C\u0443\u0434\u0440\u044B)</em>, \u0442\u0432\u043E\u0440\u044F\u0449\u0438\u0435 \u043C\u0433\u043D\u043E\u0432\u0435\u043D\u043D\u043E \u0430\u0432\u0435\u0448\u0443 .</p></div><div class="stanza"><a href="#s7.29b-30a" id="s7.29b-30a" class="num">7.29b-30a</a><p>\u0421\u043B\u043E\u0436\u0438\u0432 \u0440\u0443\u043A\u0438 \u0432 <em>\u0430\u043D\u0434\u0436\u0430\u043B\u0438 (\u043C\u0443\u0434\u0440\u0443)</em>, \u043F\u0443\u0441\u0442\u044C \u043C\u0443\u0434\u0440\u044B\u0439 \u043F\u043E\u0434\u043D\u0435\u0441\u0435\u0442 \u0431\u043E\u043B\u044C\u0448\u0438\u0435 \u043F\u0430\u043B\u044C\u0446\u044B \u043A \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u0438\u044E \u0441\u0440\u0435\u0434\u043D\u0438\u0445 (\u043F\u0430\u043B\u044C\u0446\u0435\u0432). \u042D\u0442\u0430 <em>\u0430\u0432\u0430\u0445\u0430\u043D\u0430 (\u043C\u0443\u0434\u0440\u0430</em> \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442\u0441\u044F) \u0441 \u043C\u0430\u043D\u0442\u0440\u043E\u0439 \u0432 \u0440\u0438\u0442\u0443\u0430\u043B\u0435 (\u043F\u0440\u0438\u0437\u044B\u0432\u0430\u043D\u0438\u044F) .</p></div><div class="stanza"><a href="#s7.30b" id="s7.30b" class="num">7.30b</a><p>\u0411\u043E\u043B\u044C\u0448\u0438\u0435 \u043F\u0430\u043B\u044C\u0446\u044B \u043A\u043B\u0430\u0434\u0443\u0442\u0441\u044F \u043D\u0430 \u043A\u0443\u043B\u0430\u043A\u0438 - \u044D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F <em>\u0441\u0442\u0445\u0430\u043F\u0430\u043D\u0438 (\u043C\u0443\u0434\u0440\u043E\u0439)</em> .</p></div><div class="stanza"><a href="#s7.31" id="s7.31" class="num">7.31</a><p>\u041E\u0431\u0430 \u0431\u043E\u043B\u044C\u0448\u0438\u0445 \u043F\u0430\u043B\u044C\u0446\u0430 \u043F\u043E\u043C\u0435\u0449\u0430\u044E\u0442\u0441\u044F \u0432\u043D\u0443\u0442\u0440\u0438 (\u0441\u0432\u0435\u0434\u0435\u043D\u043D\u044B\u0445 \u043A\u0443\u043B\u0430\u043A\u043E\u0432)- \u044D\u0442\u043E \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E \u043A\u0430\u043A <em>\u0441\u0430\u043D\u0438\u0440\u043E\u0434\u0445\u0438\u043D\u0438 (\u043C\u0443\u0434\u0440\u0430)</em>, \u0438\u043C\u0435\u043D\u0443\u0435\u043C\u0430\u044F \u0442\u0430\u043A\u0436\u0435 <em>\u0434\u0440\u0430\u0432\u044C\u044F\u0434\u0430</em> (\u0434\u0430\u044E\u0449\u0435\u0439 \u0431\u043E\u0433\u0430\u0442\u0441\u0442\u0432\u043E) .</p></div><div class="stanza"><a href="#s7.32" id="s7.32" class="num">7.32</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043B\u043E\u0436\u0438\u0442\u044C \u043B\u0430\u0434\u043E\u043D\u0438 \u0441 \u0432\u044B\u0442\u044F\u043D\u0443\u0442\u044B\u043C\u0438 \u043F\u0430\u043B\u044C\u0446\u0430\u043C\u0438 \u043F\u0435\u0440\u0435\u0434 \u0441\u0435\u0440\u0434\u0446\u0435\u043C- \u044D\u0442\u043E <em>\u043D\u0430\u043C\u0430\u0441\u043A\u0430\u0440\u0430 \u043C\u0443\u0434\u0440\u0430</em> (\u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442\u0441\u044F) \u043F\u0440\u0438 (\u043F\u0440\u043E\u0438\u0437\u043D\u0435\u0441\u0435\u043D\u0438\u0438) \u043C\u0430\u043D\u0442\u0440 \u0438 \u043C\u043E\u043B\u0438\u0442\u0432 .</p></div><div class="stanza"><a href="#s7.33" id="s7.33" class="num">7.33</a><p>\u041F\u0430\u043B\u044C\u0446\u044B (\u043B\u0435\u0432\u043E\u0439 \u0438 \u043F\u0440\u0430\u0432\u043E\u0439 \u0440\u0443\u043A\u0438) \u043F\u0435\u0440\u0435\u043F\u043B\u0435\u0442\u0430\u044E\u0442\u0441\u044F \u0434\u0440\u0443\u0433 \u0441 \u0434\u0440\u0443\u0433\u043E\u043C. \u041C\u0438\u0437\u0438\u043D\u0435\u0446 \u043F\u0440\u0430\u0432\u043E\u0439 \u0440\u0443\u043A\u0438 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0435\u0434\u0438\u043D\u0438\u0442\u044C \u0441 \u043A\u043E\u043D\u0447\u0438\u043A\u043E\u043C \u0431\u0435\u0437\u044B\u043C\u044F\u043D\u043D\u043E\u0433\u043E</p></div><div class="stanza"><a href="#s7.34" id="s7.34" class="num">7.34</a><p>\u041B\u0435\u0432\u044B\u0439 \u0443\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0439 \u043F\u0430\u043B\u0435\u0446 \u0441\u043E\u0435\u0434\u0438\u043D\u044F\u0435\u0442\u0441\u044F \u0441\u043E \u0441\u0440\u0435\u0434\u043D\u0438\u043C \u043F\u0430\u043B\u044C\u0446\u0435\u043C \u043F\u0440\u0430\u0432\u043E\u0439 (\u0440\u0443\u043A\u0438). \u0411\u043E\u043B\u044C\u0448\u0438\u0435 \u043F\u0430\u043B\u044C\u0446\u044B \u0440\u0430\u0437\u043C\u0435\u0449\u0430\u044E\u0442\u0441\u044F \u0443 \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u0438\u044F \u0441\u0440\u0435\u0434\u043D\u0438\u0445 \u043F\u0430\u043B\u044C\u0446\u0435\u0432. \u042D\u0442\u0430 <em>(\u0430\u043C\u0440\u0438\u0442\u0430\u043A\u0430\u0440\u0430\u043D\u0430) \u043C\u0443\u0434\u0440\u0430</em> \u044F\u0432\u043B\u044F\u0435\u0442 \u0430\u043C\u0440\u0438\u0442\u0443 (<em>\u043E\u043D\u0430 \u0436\u0435 \u0434\u0445\u0435\u043D\u0443 \u043C\u0443\u0434\u0440\u0430</em>) .</p></div><div class="stanza"><a href="#s7.35" id="s7.35" class="num">7.35</a><p>\u0423 \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u0438\u044F \u043F\u0443\u043F\u043A\u0430 \u043F\u043E\u043C\u0435\u0449\u0430\u0435\u0442\u0441\u044F \u043F\u0440\u0430\u0432\u0430\u044F (\u0440\u0443\u043A\u0430) \u043F\u043E\u0432\u0435\u0440\u0445 \u043B\u0435\u0432\u043E\u0439. \u0411\u043E\u043B\u044C\u0448\u043E\u0439 \u0438 \u0443\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0439 \u043F\u0430\u043B\u044C\u0446\u044B \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u044B \u0438 \u043E\u0431\u0440\u0430\u0449\u0435\u043D\u044B \u0432\u0432\u0435\u0440\u0445 \u043F\u0440\u0438 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0435 \u0439\u043E\u0433\u0438 (<em>\u0434\u0445\u044C\u044F\u043D\u0430 \u043C\u0443\u0434\u0440\u0430</em>) .</p></div><div class="stanza"><a href="#s7.36" id="s7.36" class="num">7.36</a><p>\u042D\u0442\u043E \u0441\u043E\u0431\u0440\u0430\u043D\u0438\u0435 \u043C\u0443\u0434\u0440 \u043C\u0443\u0434\u0440\u0435\u0446, \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u044F\u0449\u0438\u0439 \u043C\u0430\u043D\u0442\u0440\u0443, \u0434\u043E\u043B\u0436\u0435\u043D \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0442\u044C \u0432 \u0441\u0435\u0440\u0434\u0446\u0435. \u041F\u0440\u0438 \u0432\u044B\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u0438 \u0432\u0441\u0435\u0445 \u0438\u0445 \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u0438\u0442\u0441\u044F: \u041E\u041C \u0425\u0420\u0418\u041C, \u0438\u043C\u044F (\u043C\u0443\u0434\u0440\u044B), \u0437\u0430\u0442\u0435\u043C \u041D\u0410\u041C\u0410\u0425 .</p></div><p>\u0422\u0430\u043A\u043E\u0432\u0430 \u0432 \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0439 \xAB\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u0430 \u0442\u0430\u043D\u0442\u0440\u0435\xBB \u0441\u0435\u0434\u044C\u043C\u0430\u044F \u0433\u043B\u0430\u0432\u0430 (\u0438\u043C\u0435\u043D\u0443\u0435\u043C\u0430\u044F) \xAB\u0413\u043B\u0430\u0432\u0430 \u043E \u043C\u0443\u0434\u0440\u0430\u0445\xBB.</p>',30),p=[d];function n(c,l,t,v,r,f){return e(),a("div",null,p)}var _=s(i,[["render",n]]);export{h as __pageData,_ as default};
